def updateEnable(startXmitter, endXmitter, doEnable):
	base_path = '/'.join(tagPath.split('/')[:-1])
	for x in range(startXmitter + 1, endXmitter + 1):
		base_list = [
			base_path + "/Xmitter_" + str(x).zfill(2) + ".Enabled"
		]
		system.tag.writeAsync(base_list, [doEnable])

if currentValue is None or currentValue.value is None:
	return
curr = int(currentValue.value)

if initialChange:
	updateEnable(0, curr, True)
else:
	if previousValue is None or previousValue.value is None:
		updateEnable(0, curr, True)
		return
	prev = int(previousValue.value)
	if prev < curr:
		updateEnable(prev, curr, True)
	elif prev > curr:
		updateEnable(curr, prev, False)
